import React, { useState } from 'react';
import { GripVertical, Check, Calendar, MessageSquare, Paperclip } from 'lucide-react';

const TaskList = () => {
  const [tasks, setTasks] = useState([
    { id: '1', title: '사용자 온보딩 완료', status: 'todo', tag: { name: '마케팅', color: 'text-indigo-600 bg-indigo-50' }, dueDate: '내일', comments: 1, userAvatar: 'https://images.unsplash.com/photo-1535711603863-10d97bc7a2d4?w=100' },
    { id: '4', title: '진행 중(WIP) 대시보드', status: 'inprogress', dueDate: '오늘', comments: 1, userAvatar: 'https://images.unsplash.com/photo-1580489944761-15a19d654956?w=100' },
    { id: '8', title: '내부 피드백 관리', status: 'completed', dueDate: '내일', userAvatar: 'https://images.unsplash.com/photo-1544005313-94ddf0286df2?w=100' }
  ]);

  const toggleTask = (id) => {
    setTasks(prev => prev.map(t => t.id === id ? { ...t, completed: !t.completed } : t));
  };

  return (
    <div className="space-y-6">
      {/* 할 일 그룹 */}
      <div className="space-y-4">
        <h3 className="text-lg font-bold text-slate-800 dark:text-white">할 일 (1)</h3>
        <div className="flex flex-col gap-3">
          {tasks.filter(t => t.status === 'todo').map(task => (
            <div key={task.id} className="flex items-center gap-4 bg-white dark:bg-[#1A222C] p-4 rounded-xl border border-slate-100 dark:border-slate-800">
              <GripVertical className="w-5 h-5 text-slate-300" />
              <input type="checkbox" checked={task.completed} onChange={() => toggleTask(task.id)} className="rounded border-slate-300 w-5 h-5" />
              <span className="text-sm font-semibold flex-1 text-slate-700 dark:text-slate-200">{task.title}</span>
              <img src={task.userAvatar} className="w-7 h-7 rounded-full" alt="Assignee" />
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default TaskList;
